const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { Pool } = require('pg');

const sqsClient = new SQSClient({ region: process.env.AWS_REGION || 'us-east-1' });
const queueUrl = process.env.SQS_QUEUE_URL;

const pool = new Pool({
  host: process.env.DB_HOST,
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 20
});

async function processMessage(message) {
  const transaction = JSON.parse(message.Body);
  
  const client = await pool.connect();
  
  try {
    const query = `
      INSERT INTO transactions (transaction_id, account_id, amount, type, timestamp)
      VALUES ($1, $2, $3, $4, $5)
    `;
    
    await client.query(query, [
      transaction.transactionId,
      transaction.accountId,
      transaction.amount,
      transaction.type,
      transaction.timestamp || new Date().toISOString()
    ]);
    
    await client.query(`
      UPDATE accounts 
      SET balance = balance + $1 
      WHERE account_id = $2
    `, [transaction.amount, transaction.accountId]);
    
    console.log(`Processed transaction ${transaction.transactionId}`);
    
  } finally {
    client.release();
  }
}

async function deleteMessage(receiptHandle) {
  const deleteParams = {
    QueueUrl: queueUrl,
    ReceiptHandle: receiptHandle
  };
  
  await sqsClient.send(new DeleteMessageCommand(deleteParams));
}

async function pollMessages() {
  while (true) {
    try {
      const receiveParams = {
        QueueUrl: queueUrl,
        MaxNumberOfMessages: 10,
        WaitTimeSeconds: 20,
        VisibilityTimeout: 30
      };
      
      const data = await sqsClient.send(new ReceiveMessageCommand(receiveParams));
      
      if (data.Messages && data.Messages.length > 0) {
        for (const message of data.Messages) {
          await processMessage(message);
          await deleteMessage(message.ReceiptHandle);
        }
      }
    } catch (error) {
      console.error('Error processing messages:', error);
    }
  }
}

pollMessages();